
-- Create skill question bank table
CREATE TABLE public.skill_question_bank (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  career_path TEXT NOT NULL,
  skill_name TEXT NOT NULL,
  question TEXT NOT NULL,
  options JSONB NOT NULL DEFAULT '[]'::jsonb,
  correct_index INTEGER NOT NULL,
  explanation TEXT NOT NULL DEFAULT '',
  difficulty TEXT NOT NULL DEFAULT 'foundational',
  module_level INTEGER NOT NULL DEFAULT 1,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.skill_question_bank ENABLE ROW LEVEL SECURITY;

-- Anyone authenticated can read questions
CREATE POLICY "Authenticated users can read questions"
  ON public.skill_question_bank
  FOR SELECT
  USING (auth.role() = 'authenticated');

-- Create indexes for efficient querying
CREATE INDEX idx_question_bank_career_skill ON public.skill_question_bank (career_path, skill_name);
CREATE INDEX idx_question_bank_difficulty ON public.skill_question_bank (difficulty);

